import{_ as o,o as l,c as a,ai as i}from"./chunks/framework.CsYGeNYI.js";const g=JSON.parse('{"title":"智能体循环","description":"","frontmatter":{"read_when":["你需要智能体循环或生命周期事件的详细说明"],"summary":"智能体循环生命周期、流和等待语义","title":"智能体循环","x-i18n":{"generated_at":"2026-02-03T10:05:11Z","model":"claude-opus-4-5","provider":"pi","source_hash":"0775b96eb3451e137297661a1095eaefb2bafeebb5f78123174a46290e18b014","source_path":"concepts/agent-loop.md","workflow":15}},"headers":[],"relativePath":"zh-CN/concepts/agent-loop.md","filePath":"zh-CN/concepts/agent-loop.md","lastUpdated":1771906665000}'),d={name:"zh-CN/concepts/agent-loop.md"};function t(c,e,s,n,r,h){return l(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="智能体循环-opensoul" tabindex="-1"><a class="header-anchor" href="#智能体循环-opensoul">#</a> 智能体循环（OpenSoul）</h1><p>智能体循环是智能体的完整&quot;真实&quot;运行：接收 → 上下文组装 → 模型推理 → 工具执行 → 流式回复 → 持久化。这是将消息转化为操作和最终回复的权威路径，同时保持会话状态的一致性。</p><p>在 OpenSoul 中，循环是每个会话的单次序列化运行，在模型思考、调用工具和流式输出时发出生命周期和流事件。本文档解释了这个真实循环是如何端到端连接的。</p><h2 id="入口点" tabindex="-1"><a class="header-anchor" href="#入口点">#</a> 入口点</h2><ul><li>Gateway 网关 RPC：<code>agent</code> 和 <code>agent.wait</code>。</li><li>CLI：<code>agent</code> 命令。</li></ul><h2 id="工作原理-高层次" tabindex="-1"><a class="header-anchor" href="#工作原理-高层次">#</a> 工作原理（高层次）</h2><ol><li><code>agent</code> RPC 验证参数，解析会话（sessionKey/sessionId），持久化会话元数据，立即返回 <code>{ runId, acceptedAt }</code>。</li><li><code>agentCommand</code> 运行智能体： <ul><li>解析模型 + 思考/详细模式默认值</li><li>加载 Skills 快照</li><li>调用 <code>runEmbeddedPiAgent</code>（pi-agent-core 运行时）</li><li>如果嵌入式循环未发出<strong>生命周期结束/错误</strong>事件，则发出该事件</li></ul></li><li><code>runEmbeddedPiAgent</code>： <ul><li>通过每会话 + 全局队列序列化运行</li><li>解析模型 + 认证配置文件并构建 pi 会话</li><li>订阅 pi 事件并流式传输助手/工具增量</li><li>强制执行超时 -&gt; 超时则中止运行</li><li>返回有效负载 + 使用元数据</li></ul></li><li><code>subscribeEmbeddedPiSession</code> 将 pi-agent-core 事件桥接到 OpenSoul <code>agent</code> 流： <ul><li>工具事件 =&gt; <code>stream: &quot;tool&quot;</code></li><li>助手增量 =&gt; <code>stream: &quot;assistant&quot;</code></li><li>生命周期事件 =&gt; <code>stream: &quot;lifecycle&quot;</code>（<code>phase: &quot;start&quot; | &quot;end&quot; | &quot;error&quot;</code>）</li></ul></li><li><code>agent.wait</code> 使用 <code>waitForAgentJob</code>： <ul><li>等待 <code>runId</code> 的<strong>生命周期结束/错误</strong></li><li>返回 <code>{ status: ok|error|timeout, startedAt, endedAt, error? }</code></li></ul></li></ol><h2 id="队列-并发" tabindex="-1"><a class="header-anchor" href="#队列-并发">#</a> 队列 + 并发</h2><ul><li>运行按会话键（会话通道）序列化，可选择通过全局通道。</li><li>这可以防止工具/会话竞争并保持会话历史的一致性。</li><li>消息渠道可以选择队列模式（collect/steer/followup）来馈送此通道系统。参见<a href="/docs/concepts/queue">命令队列</a>。</li></ul><h2 id="会话-工作区准备" tabindex="-1"><a class="header-anchor" href="#会话-工作区准备">#</a> 会话 + 工作区准备</h2><ul><li>解析并创建工作区；沙箱隔离运行可能会重定向到沙箱工作区根目录。</li><li>加载 Skills（或从快照中复用）并注入到环境和提示中。</li><li>解析引导/上下文文件并注入到系统提示报告中。</li><li>获取会话写锁；在流式传输之前打开并准备 <code>SessionManager</code>。</li></ul><h2 id="提示组装-系统提示" tabindex="-1"><a class="header-anchor" href="#提示组装-系统提示">#</a> 提示组装 + 系统提示</h2><ul><li>系统提示由 OpenSoul 的基础提示、Skills 提示、引导上下文和每次运行的覆盖构建。</li><li>强制执行模型特定的限制和压缩保留令牌。</li><li>参见<a href="/docs/concepts/system-prompt">系统提示</a>了解模型看到的内容。</li></ul><h2 id="钩子点-可以拦截的位置" tabindex="-1"><a class="header-anchor" href="#钩子点-可以拦截的位置">#</a> 钩子点（可以拦截的位置）</h2><p>OpenSoul 有两个钩子系统：</p><ul><li><strong>内部钩子</strong>（Gateway 网关钩子）：用于命令和生命周期事件的事件驱动脚本。</li><li><strong>插件钩子</strong>：智能体/工具生命周期和 Gateway 网关管道中的扩展点。</li></ul><h3 id="内部钩子-gateway-网关钩子" tabindex="-1"><a class="header-anchor" href="#内部钩子-gateway-网关钩子">#</a> 内部钩子（Gateway 网关钩子）</h3><ul><li><strong><code>agent:bootstrap</code></strong>：在系统提示最终确定之前构建引导文件时运行。用于添加/删除引导上下文文件。</li><li><strong>命令钩子</strong>：<code>/new</code>、<code>/reset</code>、<code>/stop</code> 和其他命令事件（参见钩子文档）。</li></ul><p>参见<a href="/docs/automation/hooks">钩子</a>了解设置和示例。</p><h3 id="插件钩子-智能体-gateway-网关生命周期" tabindex="-1"><a class="header-anchor" href="#插件钩子-智能体-gateway-网关生命周期">#</a> 插件钩子（智能体 + Gateway 网关生命周期）</h3><p>这些在智能体循环或 Gateway 网关管道内运行：</p><ul><li><strong><code>before_agent_start</code></strong>：在运行开始前注入上下文或覆盖系统提示。</li><li><strong><code>agent_end</code></strong>：在完成后检查最终消息列表和运行元数据。</li><li><strong><code>before_compaction</code> / <code>after_compaction</code></strong>：观察或注释压缩周期。</li><li><strong><code>before_tool_call</code> / <code>after_tool_call</code></strong>：拦截工具参数/结果。</li><li><strong><code>tool_result_persist</code></strong>：在工具结果写入会话记录之前同步转换它们。</li><li><strong><code>message_received</code> / <code>message_sending</code> / <code>message_sent</code></strong>：入站 + 出站消息钩子。</li><li><strong><code>session_start</code> / <code>session_end</code></strong>：会话生命周期边界。</li><li><strong><code>gateway_start</code> / <code>gateway_stop</code></strong>：Gateway 网关生命周期事件。</li></ul><p>参见<a href="/docs/tools/plugin#plugin-hooks">插件</a>了解钩子 API 和注册详情。</p><h2 id="流式传输-部分回复" tabindex="-1"><a class="header-anchor" href="#流式传输-部分回复">#</a> 流式传输 + 部分回复</h2><ul><li>助手增量从 pi-agent-core 流式传输并作为 <code>assistant</code> 事件发出。</li><li>分块流式传输可以在 <code>text_end</code> 或 <code>message_end</code> 时发出部分回复。</li><li>推理流式传输可以作为单独的流或作为块回复发出。</li><li>参见<a href="/docs/concepts/streaming">流式传输</a>了解分块和块回复行为。</li></ul><h2 id="工具执行-消息工具" tabindex="-1"><a class="header-anchor" href="#工具执行-消息工具">#</a> 工具执行 + 消息工具</h2><ul><li>工具开始/更新/结束事件在 <code>tool</code> 流上发出。</li><li>工具结果在记录/发出之前会对大小和图像有效负载进行清理。</li><li>消息工具发送会被跟踪以抑制重复的助手确认。</li></ul><h2 id="回复整形-抑制" tabindex="-1"><a class="header-anchor" href="#回复整形-抑制">#</a> 回复整形 + 抑制</h2><ul><li>最终有效负载由以下内容组装： <ul><li>助手文本（和可选的推理）</li><li>内联工具摘要（当详细模式 + 允许时）</li><li>模型出错时的助手错误文本</li></ul></li><li><code>NO_REPLY</code> 被视为静默令牌，从出站有效负载中过滤。</li><li>消息工具重复项从最终有效负载列表中移除。</li><li>如果没有剩余可渲染的有效负载且工具出错，则发出回退工具错误回复（除非消息工具已经发送了用户可见的回复）。</li></ul><h2 id="压缩-重试" tabindex="-1"><a class="header-anchor" href="#压缩-重试">#</a> 压缩 + 重试</h2><ul><li>自动压缩发出 <code>compaction</code> 流事件，可以触发重试。</li><li>重试时，内存缓冲区和工具摘要会重置以避免重复输出。</li><li>参见<a href="/docs/concepts/compaction">压缩</a>了解压缩管道。</li></ul><h2 id="事件流-当前" tabindex="-1"><a class="header-anchor" href="#事件流-当前">#</a> 事件流（当前）</h2><ul><li><code>lifecycle</code>：由 <code>subscribeEmbeddedPiSession</code> 发出（以及作为 <code>agentCommand</code> 的回退）</li><li><code>assistant</code>：从 pi-agent-core 流式传输的增量</li><li><code>tool</code>：从 pi-agent-core 流式传输的工具事件</li></ul><h2 id="聊天渠道处理" tabindex="-1"><a class="header-anchor" href="#聊天渠道处理">#</a> 聊天渠道处理</h2><ul><li>助手增量被缓冲到聊天 <code>delta</code> 消息中。</li><li>在<strong>生命周期结束/错误</strong>时发出聊天 <code>final</code>。</li></ul><h2 id="超时" tabindex="-1"><a class="header-anchor" href="#超时">#</a> 超时</h2><ul><li><code>agent.wait</code> 默认：30 秒（仅等待）。<code>timeoutMs</code> 参数可覆盖。</li><li>智能体运行时：<code>agents.defaults.timeoutSeconds</code> 默认 600 秒；在 <code>runEmbeddedPiAgent</code> 中止计时器中强制执行。</li></ul><h2 id="可能提前结束的情况" tabindex="-1"><a class="header-anchor" href="#可能提前结束的情况">#</a> 可能提前结束的情况</h2><ul><li>智能体超时（中止）</li><li>AbortSignal（取消）</li><li>Gateway 网关断开连接或 RPC 超时</li><li><code>agent.wait</code> 超时（仅等待，不会停止智能体）</li></ul>',39)])])}const p=o(d,[["render",t]]);export{g as __pageData,p as default};
